+#[test]
+fn public_backend_surface_advertises_only_supported_semantic_backend() {
+    let tiers = advertised_embedder_tiers(true, true);
+    assert_eq!(
+        tiers,
+        vec![
+            "hash".to_string(),
+            "fastembed".to_string(),
+            "cross-encoder".to_string(),
+        ]
+    );
